type Session struct {
	ID       string `json:"id"`
	Preferences map[string]string `json:"preferences"`
	Permissions []string `json:"permissions"`
}

func main() {
	store := sessions.NewFileStore("sessions/")

	gob.Register(Session{})

	sess, err := store.Get(os.Getenv("SESSION_NAME"), "default")
	if err != nil {
		log.Fatal(err)
	}

	if sess.IsNew() {
		userID := "12345"
		preferences := map[string]string{"lang": "en", "theme": "light"}
		permissions := []string{"read", "write"}

		sess.Values["user_id"] = userID
		sess.Values["preferences"] = preferences
		sess.Values["permissions"] = permissions

		err = store.Save(os.Getenv("SESSION_NAME"), sess)
		if err != nil {
			log.Fatal(err)
		}
	}

	userID := sess.Values["user_id"].(string)
	preferences := sess.Values["preferences"].([]map[string]string)[0]
	permissions := sess.Values["permissions"].([]interface{})[0].([]string)

	fmt.Println("User ID:", userID)
	fmt.Println("Preferences:", preferences)
	fmt.Println("Permissions:", permissions)
}

func loadSession(store *sessions.FileStore, sessionName string) (*sessions.Session, error) {
	filePath := filepath.Join(store.Path(), sessionName+".gob")
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, err
	}
	sess, err := store.Get(sessionName, "default")
	if err != nil {
		return nil, err
	}

	err = gob.Unmarshal(data, sess.Values)
	if err != nil {
		return nil, err
	}

	return sess, nil
}